import osimport asyncioimport base64from io import BytesIOfrom flask import Flask, request, jsonifyfrom telethon import TelegramClientfrom tg_messages import get_chat_previewfrom tg_search import search_chatsfrom tg_send import send_messagesfrom tg_utils import get_chats_infofrom tg_utils import get_all_foldersfrom tg_utils import update_chat_foldersapp = Flask(__name__)API_ID = int(os.getenv("API_ID", 30101072))API_HASH = os.getenv("API_HASH", "e0f3d73a25cc1c3084fb3341fb526955")PHONE = os.getenv("PHONE", "+79204962556")DEVICE_PARAMS = {    "device_model": "Samsung S23 Ultra",    "system_version": "Android 13",    "app_version": "9.6.1",    "lang_code": "en",    "system_lang_code": "en-US"}client = TelegramClient(    'session_web',    API_ID,    API_HASH,    device_model=DEVICE_PARAMS["device_model"],    system_version=DEVICE_PARAMS["system_version"],    app_version=DEVICE_PARAMS["app_version"],    lang_code=DEVICE_PARAMS["lang_code"],    system_lang_code=DEVICE_PARAMS["system_lang_code"])loop = asyncio.new_event_loop()asyncio.set_event_loop(loop)async def ensure_connected():    """Проверяет и восстанавливает соединение"""    if not client.is_connected():        print("⚠️ Переподключение...")        await client.connect()        if not await client.is_user_authorized():            await client.start(PHONE)def run_async(coro):    """Запускает корутину с проверкой соединения"""    async def wrapper():        await ensure_connected()        return await coro    return loop.run_until_complete(wrapper())async def auth():    max_retries = 3    for attempt in range(max_retries):        try:            await client.start(PHONE)            print("✅ Telegram готов")            return        except (ConnectionError, TimeoutError, OSError) as e:            print(f"⚠️ Ошибка авторизации (попытка {attempt+1}/{max_retries}): {e}")            if attempt < max_retries - 1:                await asyncio.sleep(5)                await client.disconnect()                await client.connect()            else:                raiserun_async(auth())async def get_avatar(entity):    """Асинхронное получение аватара без записи на диск"""    try:        buffer = BytesIO()        await client.download_profile_photo(entity, file=buffer)        if buffer.getvalue():            return base64.b64encode(buffer.getvalue()).decode('utf-8')    except Exception as e:        print(f"Avatar error: {e}")    return None@app.route('/api/chats/all')def get_all_chats():    async def fetch():        result = []        count = 0        async for d in client.iter_dialogs():            username = getattr(d.entity, 'username', None)            if not username:                phone = getattr(d.entity, 'phone', None)                if phone:                    username = phone            result.append({                'id': d.id,                'name': d.name,                'username': username,                'avatar': await get_avatar(d.entity)            })            count += 1            if count % 50 == 0:                print(f"Загружено {count} чатов...")                await asyncio.sleep(0.3)        return result    try:        data = run_async(fetch())        print(f"Всего загружено чатов: {len(data)}")        return jsonify(data)    except Exception as e:        print(f"Ошибка /api/chats/all: {e}")        return jsonify([]), 500@app.route('/api/folders/update', methods=['POST'])def update_folders():    try:        data = request.json        folder_id = data.get('folderId')        chat_ids = data.get('chatIds', [])        add_to_folder = data.get('addOperationFlag', True)        if not folder_id:            return jsonify({'error': 'Не указан ID папки'}), 400        if not chat_ids:            return jsonify({'error': 'Не указаны ID чатов'}), 400        print(f"🔵 Обновление папки {folder_id}: {'добавление' if add_to_folder else 'удаление'} {len(chat_ids)} чатов")        result = run_async(update_chat_folders(client, folder_id, chat_ids, add_to_folder))        return jsonify(result)    except Exception as e:        print(f"🔴 Ошибка обновления папки: {e}")        return jsonify({'error': str(e)}), 500@app.route('/api/search', methods=['POST'])def search():    try:        data = request.json        print(f"🔵 Получены данные от Java: {data}")        messages_count = data.get('messagesCount', 0)        if messages_count is None:            messages_count = 0        params = {            'term': data.get('term', 'Java'),            'lastMessage': data.get('lastMessage', '').strip(),            'maxFoundCount': data.get('maxFoundCount', 10),            'minDiffDaysCount': data.get('minDiffDaysCount', 7),            'botType': data.get('botType', 'PERSONAL'),            'groupType': data.get('groupType', 'PERSONAL'),            'excludeChatIds': data.get('excludeChatIds', []),            'messagesCount': messages_count        }        print(f"🔵 Параметры поиска: {params}")        found_chats = run_async(search_chats(client, params))        async def add_avatars(chats):            for chat in chats:                try:                    entity = await client.get_entity(chat['id'])                    chat['avatar'] = await get_avatar(entity)                except Exception as e:                    print(f"Avatar error for {chat.get('name')}: {e}")            return chats        found_chats = run_async(add_avatars(found_chats))        return jsonify(found_chats)    except Exception as e:        print(f"🔴 Ошибка в search: {e}")        return jsonify([]), 500@app.route('/api/chat-preview/<chat_id>')def chat_preview(chat_id):    try:        chat_id = int(chat_id)    except ValueError:        return jsonify({'error': 'Invalid chat_id'}), 400    limit = request.args.get('limit', default=None, type=int)    if limit == 0:        limit = None    try:        result = run_async(get_chat_preview(client, chat_id, limit))        return jsonify(result)    except Exception as e:        print(f"Ошибка preview: {e}")        return jsonify({'messages': []}), 500@app.route('/api/send_bulk_messages', methods=['POST'])def send_bulk_messages():    try:        data = request.json        print(f"🔵 Получены данные: {data}")        if 'contactUsernames' in data:            chat_ids = data['contactUsernames']        elif 'contactIds' in data:            chat_ids = data['contactIds']        else:            chat_ids = []        message_text = data.get('messageText', '')        delay = data.get('delaySeconds', 2)        only_new_chats = data.get('onlyNewChats', False)        if not chat_ids:            return jsonify({'error': 'Нет чатов'}), 400        if not message_text:            return jsonify({'error': 'Нет текста'}), 400        results = run_async(send_messages(client, chat_ids, message_text, delay, only_new_chats))        success_count = len([r for r in results if r['status'] == 'success'])        skipped_count = len([r for r in results if r['status'] == 'skipped'])        error_count = len([r for r in results if r['status'] == 'error'])        return jsonify({            'total': len(chat_ids),            'success': success_count,            'skipped': skipped_count,            'error': error_count,            'results': results        })    except Exception as e:        print(f"❌ Ошибка: {e}")        return jsonify({'error': str(e)}), 500@app.route('/api/export/<int:chat_id>')def export_chat(chat_id):    async def export():        chat_name = str(chat_id)        async for d in client.iter_dialogs():            if d.id == chat_id:                chat_name = d.name                break        messages = []        async for m in client.iter_messages(chat_id, limit=5000):            messages.append({'id': m.id, 'date': str(m.date), 'text': m.text[:500] if m.text else None})        os.makedirs('exports', exist_ok=True)        filename = f'exports/{chat_name.replace("/", "_").replace(" ", "_")}.json'        with open(filename, 'w', encoding='utf-8') as f:            import json            json.dump({                'chat_id': chat_id,                'chat_name': chat_name,                'total_messages': len(messages),                'messages': messages            }, f, ensure_ascii=False, indent=2)        return {'filename': filename, 'total': len(messages)}    try:        result = run_async(export())        return jsonify(result)    except Exception as e:        return jsonify({'error': str(e)}), 500@app.route('/api/folders', methods=['GET'])def get_folders():    try:        folders = run_async(get_all_folders(client))        return jsonify(folders)    except Exception as e:        print(f"❌ Ошибка получения папок: {e}")        return jsonify([]), 500@app.route('/api/chats/info', methods=['POST'])def get_chats_info_endpoint():    try:        data = request.json        chat_ids = data.get('chat_ids', [])        if not chat_ids:            return jsonify({'error': 'Нет ID чатов'}), 400        print(f"🔵 Запрос информации о {len(chat_ids)} чатах")        results = run_async(get_chats_info(client, chat_ids))        return jsonify({            'total': len(chat_ids),            'success': len([r for r in results if r.get('name') is not None]),            'error': len([r for r in results if r.get('error')]),            'results': results        })    except Exception as e:        print(f"🔴 Ошибка в /api/chats/info: {e}")        return jsonify({'error': str(e)}), 500if __name__ == '__main__':    print("🚀 Сервер на http://localhost:8081")    app.run(debug=False, port=8081, threaded=False)